// Combine results from all three sources
const vsdResult = $node["1️⃣ Fetch VSD (Tin Tức)"].json;
const hnxResult = $node["2️⃣ Fetch HNX (Trái Phiếu)"].json;
const hoseResult = $node["3️⃣ Fetch HOSE (Chứng Chỉ)"].json;

// Merge all data from three sources
const allRecords = [];
const recordMap = {};

// Add VSD records
if (vsdResult?.data && Array.isArray(vsdResult.data)) {
  vsdResult.data.forEach(record => {
    allRecords.push({ ...record, source: 'VSD' });
    recordMap[record.code] = record;
  });
}

// Add HNX records (if not already in VSD)
if (hnxResult?.data && Array.isArray(hnxResult.data)) {
  hnxResult.data.forEach(record => {
    if (!recordMap[record.code]) {
      allRecords.push({ ...record, source: 'HNX' });
      recordMap[record.code] = record;
    }
  });
}

// Add HOSE records (if not already in other sources)
if (hoseResult?.data && Array.isArray(hoseResult.data)) {
  hoseResult.data.forEach(record => {
    if (!recordMap[record.code]) {
      allRecords.push({ ...record, source: 'HOSE' });
      recordMap[record.code] = record;
    }
  });
}

return [{
  vsd_count: vsdResult?.count || 0,
  hnx_count: hnxResult?.count || 0,
  hose_count: hoseResult?.count || 0,
  total_unique: allRecords.length,
  vsd_status: vsdResult?.status,
  hnx_status: hnxResult?.status,
  hose_status: hoseResult?.status,
  all_records: allRecords,
  vsd_data: vsdResult,
  hnx_data: hnxResult,
  hose_data: hoseResult,
  collected_at: new Date().toISOString()
}];

const records = $input.all().map(item => item.json);
const combined = $node["4️⃣ Combine Results"].json;
const timestamp = new Date().toLocaleString('vi-VN');

const summary = {
  total: records.length,
  vsd: combined.vsd_count,
  hnx: combined.hnx_count,
  hose: combined.hose_count,
  total_unique: combined.total_unique,
  pending_confirmation: records.filter(r => r.confirmation_status === 'awaiting_review').length
};

const markdown = `# Kết Quả Thu Thập Thông Tin Quyền Chứng Khoán

## 📊 Thống Kê

- **Cập nhật lúc:** ${timestamp}
- **Tổng bản ghi (duy nhất):** ${summary.total}
  - VSD: ${summary.vsd}
  - HNX: ${summary.hnx}
  - HOSE: ${summary.hose}
- **Chờ xác nhận:** ${summary.pending_confirmation}

---

## 📋 Chi Tiết Từng Mã

${records.map((r, idx) => `
### ${idx + 1}. ${r.symbol}

**Thông tin chứng khoán:**

| Trường | Giá trị |
|-------|--------|
| Mã chứng khoán | ${r.mã_chứng_khoán} |
| Tên tổ chức đăng ký | ${r.tên_tổ_chức_đăng_ký} |
| Tên chứng khoán | ${r.tên_chứng_khoán} |
| Mã ISIN | ${r.mã_isin} |
| Nơi giao dịch | ${r.nơi_giao_dịch} |
| Loại chứng khoán | ${r.loại_chứng_khoán} |
| Ngày đăng ký cuối | ${r.ngày_đăng_ký_cuối} |
| Lý do/Mục đích | ${r.lý_do_mục_đích} |
| Tỷ lệ thực hiện | ${r.tỷ_lệ_thực_hiện} |
| Thời gian thực hiện | ${r.thời_gian_thực_hiện} |
| Địa điểm thực hiện | ${r.địa_điểm_thực_hiện} |

**Quyền:**
- **Nhận lãi:** ${r.quyền_nhận_lãi}
- **Trả gốc:** ${r.quyền_trả_gốc}
- **Chuyển đổi:** ${r.quyền_chuyển_đổi}

**Nguồn:** ${r.source} | **Trạng thái xác nhận:** ${r.confirmation_status}

[Xem chi tiết](${r.url})

---
`).join('\n')};

return [{
  markdown: markdown,
  records: records,
  summary: summary,
  timestamp: new Date().toISOString()
}];

return [{
  status: 'success',
  message: 'Workflow hoàn thành!',
  timestamp: new Date().toISOString(),
  next_step: 'Mở web interface để review dữ liệu'
}];
